import{_ as t,c as a,o as s,a5 as i}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"Watch Mode Configuration","titleTemplate":"NpgsqlRest","description":"Configuration reference for NpgsqlRest watch mode (--watch): restart the server or re-run tests on SQL file, configuration, and database routine changes.","frontmatter":{"outline":[2,3],"title":"Watch Mode Configuration","titleTemplate":"NpgsqlRest","description":"Configuration reference for NpgsqlRest watch mode (--watch): restart the server or re-run tests on SQL file, configuration, and database routine changes.","head":[["meta",{"name":"keywords","content":"npgsqlrest watch mode, --watch, dev server reload, database polling, sql hot reload, postgresql rest api dev loop"}],["meta",{"property":"og:title","content":"NpgsqlRest Watch Mode Configuration"}],["meta",{"property":"og:description","content":"Configuration reference for NpgsqlRest watch mode (--watch)."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/config/watch.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/config/watch.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest Watch Mode Configuration"}],["meta",{"name":"twitter:description","content":"Configuration reference for NpgsqlRest watch mode (--watch)."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"config/watch.md","filePath":"config/watch.md","lastUpdated":1782480183000}'),n={name:"config/watch.md"};function o(r,e,l,d,h,c){return s(),a("div",null,e[0]||(e[0]=[i(`<h1 id="watch-mode" tabindex="-1">Watch Mode <a class="header-anchor" href="#watch-mode" aria-label="Permalink to &quot;Watch Mode&quot;">​</a></h1><p>Configuration for <strong>watch mode</strong> — one feature, two flavors selected by the <code>--test</code> flag:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Command</th><th>Flavor</th><th>Watches</th><th>On change</th></tr></thead><tbody><tr><td><code>npgsqlrest ... --test --watch</code></td><td><strong>Test watch</strong></td><td>test files, included fixtures/profiles, endpoint SQL files, the database</td><td>changed test re-runs alone; endpoint or database change rebuilds endpoints in-process and re-runs everything</td></tr><tr><td><code>npgsqlrest ... --watch</code></td><td><strong>Server watch</strong></td><td>the SQL file source tree, the configuration files, the database</td><td>the server restarts (~1s)</td></tr></tbody></table></div></div><p>Watch is interactive/dev-only. In both flavors a broken SQL file cannot kill the session — <code>SqlFileSource.ErrorMode</code> is forced from <code>Exit</code> to <code>Skip</code> while watching.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>Watch</code> section is <strong>top-level</strong> (a sibling of <code>NpgsqlRest</code>, not nested inside it), because it drives both flavors:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Watch</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Enabled</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> false</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">DatabasePollingInterval</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;2s&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></details><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Setting</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Enabled</code></td><td>bool</td><td><code>false</code></td><td>Turn watch mode on. The <code>--watch</code> CLI flag is the shorthand for this setting.</td></tr><tr><td><code>DatabasePollingInterval</code></td><td>string</td><td><code>&quot;2s&quot;</code></td><td>Poll the database for routine changes; <code>0</code> disables polling.</td></tr></tbody></table></div></div><h2 id="enabled" tabindex="-1">Enabled <a class="header-anchor" href="#enabled" aria-label="Permalink to &quot;Enabled&quot;">​</a></h2><p>Turns watch mode on; <code>--watch</code> on the command line is equivalent. The flavor is chosen by <code>--test</code>:</p><details class="code-collapsible" open><summary>sh</summary><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">npgsqlrest</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> ./config.json</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> --watch</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">               # server watch</span></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">npgsqlrest</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> ./config.json</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> --test</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> --watch</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">        # test watch</span></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">npgsqlrest</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> ./config.json</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> --watch:enabled=true</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">  # same as --watch (standard config override syntax)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p><strong>Server watch</strong> needs something to watch: an enabled <a href="./sql-file-source.html">SQL file source</a>, database polling (on by default), or both — with neither, <code>--watch</code> exits with an error. Test watch always has its test files to watch.</p><h2 id="databasepollinginterval" tabindex="-1">DatabasePollingInterval <a class="header-anchor" href="#databasepollinginterval" aria-label="Permalink to &quot;DatabasePollingInterval&quot;">​</a></h2><p>Routine-source endpoints (functions and procedures) have no files to watch — so watch mode polls the <strong>database</strong> instead, with perfect fidelity: the poll runs the <strong>same routine discovery query the endpoint source uses</strong>, with the same configured filters (schema/name/language includes and excludes), hashed server-side into a single value on a dedicated non-pooled connection. If the hash changes, the discovered endpoints changed — by definition.</p><p>Detected (because they change the discovery result):</p><ul><li><code>create</code> / <code>create or replace</code> / <code>drop</code> / <code>alter</code> of functions and procedures, including <code>GRANT</code>/<code>REVOKE</code></li><li><strong><code>COMMENT ON</code></strong> — i.e. <a href="./../annotations/">annotation</a> changes</li><li>changes to the <strong>composite types and tables used as parameter or return types</strong> (<code>alter table users add column</code> reshapes a <code>returns setof users</code> endpoint even though no function changed)</li></ul><p>Never triggers (because the discovery query doesn&#39;t read them): unrelated tables, temp objects, data changes.</p><p>Accepts <code>&quot;2s&quot;</code>, <code>&quot;500ms&quot;</code>, <code>&quot;1m&quot;</code>, a plain number of seconds, or <code>&quot;hh:mm:ss&quot;</code>; <code>0</code> disables polling. Polling is automatically inactive when the routine source is disabled (<code>NpgsqlRest.RoutineOptions.Enabled: false</code>).</p><p>This makes a <strong>routines-only</strong> project fully watchable: run <code>npgsqlrest ./config.json --watch</code>, then <code>create or replace</code> a function in psql — the endpoint is live about two seconds later, annotations included. In test watch, a database change shows as <code>— change detected (database) —</code> followed by an endpoint rebuild and a full rerun; the runner re-baselines after every rerun so self-inflicted changes never re-trigger.</p><h2 id="server-watch-behavior" tabindex="-1">Server watch behavior <a class="header-anchor" href="#server-watch-behavior" aria-label="Permalink to &quot;Server watch behavior&quot;">​</a></h2><p>The process becomes a small <strong>supervisor</strong> that spawns itself as a child server and watches for changes; the child runs the completely normal server pipeline — including <strong>code generation</strong> (TypeScript client, HTTP files, OpenAPI regenerate on every restart), so dev is production behavior (the same model as <code>dotnet watch</code>).</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Event</th><th>Result</th></tr></thead><tbody><tr><td><code>.sql</code> change under the source tree</td><td>restart (files matching <code>SkipPattern</code> — test files — are ignored)</td></tr><tr><td>configuration file change</td><td>restart with the new configuration</td></tr><tr><td>database routine change (polling)</td><td>restart</td></tr><tr><td>broken SQL file</td><td>restart; the error is logged, that endpoint drops, everything else keeps serving</td></tr><tr><td>child crashes/exits on its own</td><td>supervisor waits for the next change (no crash-looping)</td></tr><tr><td>Ctrl+C / SIGTERM (<code>docker stop</code>)</td><td>child stopped gracefully, both processes exit, port freed</td></tr><tr><td>supervisor killed hard (SIGKILL)</td><td>the child detects the vanished parent and exits by itself — no orphan holding the port</td></tr></tbody></table></div></div><p>Graceful child stop uses SIGTERM on Linux/macOS; on Windows the child is hard-killed (nothing needs teardown in a dev server). Works in every distribution: AOT executables, framework-dependent <code>dotnet NpgsqlRestClient.dll</code>, and both Docker image flavors.</p><div class="tip custom-block"><p class="custom-block-title">Docker Desktop bind mounts</p><p>Where file events don&#39;t cross the filesystem boundary (Docker Desktop volume mounts, network shares), set the ecosystem-standard <code>DOTNET_USE_POLLING_FILE_WATCHER=1</code> to switch the file watcher to a 1-second polling scan. This affects file watching only — database polling is unaffected.</p></div><h2 id="test-watch-behavior" tabindex="-1">Test watch behavior <a class="header-anchor" href="#test-watch-behavior" aria-label="Permalink to &quot;Test watch behavior&quot;">​</a></h2><p>Described in detail in the <a href="./../guide/testing.html">Testing Guide</a> and the <a href="./test-runner.html#watch-mode">Test Runner configuration</a>: a changed test file re-runs alone; endpoint file and database changes rebuild endpoints in-process (with a <code>+</code>/<code>-</code> endpoint delta report) and re-run everything; <code>Teardown</code> runs once, on exit — including on Ctrl+C and SIGTERM.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../guide/testing.html">Testing Guide</a> — the test runner walkthrough</li><li><a href="./test-runner.html">Test Runner configuration</a> — test discovery, filtering, setup/teardown</li><li><a href="./sql-file-source.html">SQL File Source</a> — the endpoint file tree that server watch monitors</li><li><a href="./../guide/sql-files.html">SQL File Endpoints Guide</a> — the dev loop this feature accelerates</li></ul>`,28)]))}const u=t(n,[["render",o]]);export{g as __pageData,u as default};
